const CONFIG = {
  timezone: 'Asia/Jerusalem',
  urgencyKeywords: {
    critical: ['urgent', 'asap', 'immediately', 'critical', 'emergency', 'דחוף', 'מיידי'],
    high: ['deadline', 'due', 'must', 'required', 'payment', 'invoice', 'action required', 'תאריך יעד', 'תשלום'],
    medium: ['meeting', 'reminder', 'review', 'submit', 'approval', 'פגישה', 'תזכורת'],
    low: ['fyi', 'update', 'info', 'notice', 'newsletter', 'עדכון']
  }
};

function esc(text) {
  return (text || '').replace(/([\[\]_*`~])/g, '\\$1');
}

function fmtTime(iso) {
  if (!iso) return null;
  return new Date(iso).toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit', timeZone: CONFIG.timezone });
}

function getEmailUrgency(text) {
  const lower = (text || '').toLowerCase();
  if (CONFIG.urgencyKeywords.critical.some(w => lower.includes(w))) return '🔴';
  if (CONFIG.urgencyKeywords.high.some(w => lower.includes(w))) return '🟠';
  if (CONFIG.urgencyKeywords.medium.some(w => lower.includes(w))) return '🟡';
  return '⚪';
}

function getSender(item) {
  let from = item.from || item.From || '';
  if ((!from || !from.includes('@')) && item.payload?.headers) {
    const h = item.payload.headers.find(h => h.name?.toLowerCase() === 'from');
    if (h?.value) from = h.value;
  }
  const nameMatch = from.match(/^([^<]+)\s*</);
  return nameMatch ? nameMatch[1].trim() : from.split('@')[0] || 'Unknown';
}

// --- Build today's date header ---
const now = new Date();
const dateStr = now.toLocaleDateString('en-GB', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', timeZone: CONFIG.timezone });
const greeting = (() => {
  const hour = parseInt(now.toLocaleString('en-GB', { hour: 'numeric', hour12: false, timeZone: CONFIG.timezone }));
  if (hour < 12) return '🌅 Good Morning';
  if (hour < 17) return '☀️ Good Afternoon';
  return '🌙 Good Evening';
})();

let msg = `${greeting}, Alex!\n📆 *${dateStr}*\n`;

// --- Separate calendar items from email items ---
const allItems = $input.all();

// Calendar items have start.dateTime or start.date
const events = allItems.filter(i => i.json?.start?.dateTime || i.json?.start?.date);

// Email items have threadId or labelIds (Gmail-specific fields)
const emails = allItems.filter(i => i.json?.threadId || i.json?.labelIds);

// --- Calendar Section ---
msg += `\n━━━━━━━━━━━━━━━━━━━━\n`;
msg += `📅 *TODAY'S SCHEDULE*`;

if (events.length === 0) {
  msg += `\nNo events today ✨\n`;
} else {
  const seen = new Set();
  const uniqueEvents = events.filter(i => {
    const id = i.json.id || i.json.summary;
    if (seen.has(id)) return false;
    seen.add(id);
    return true;
  });

  msg += ` (${uniqueEvents.length} event${uniqueEvents.length > 1 ? 's' : ''})\n`;
  for (const item of uniqueEvents) {
    const ev = item.json;
    const startISO = ev.start?.dateTime || ev.start?.date;
    const endISO = ev.end?.dateTime || ev.end?.date;
    const startTime = fmtTime(startISO);
    const endTime = fmtTime(endISO);
    const isAllDay = !ev.start?.dateTime;
    const summary = ev.summary || 'Untitled';

    if (isAllDay) {
      msg += `\n🔹 *${esc(summary)}* — All day\n`;
    } else {
      msg += `\n🔹 *${esc(summary)}*\n`;
      msg += `    🕒 ${startTime} - ${endTime}\n`;
    }

    if (ev.hangoutLink) {
      msg += `    🎥 [Join Meet](${ev.hangoutLink})\n`;
    } else if (ev.location && ev.location.toLowerCase().includes('zoom')) {
      const zoomLink = ev.location.match(/https?:\/\/[^\s]+zoom[^\s]+/i);
      if (zoomLink) msg += `    🎥 [Join Zoom](${zoomLink[0]})\n`;
    } else if (ev.location && !ev.location.startsWith('http')) {
      msg += `    📍 ${esc(ev.location)}\n`;
    }

    const attendees = (ev.attendees || []).filter(a => !a.self);
    if (attendees.length > 0) {
      msg += `    👥 ${attendees.length} attendee${attendees.length > 1 ? 's' : ''}\n`;
    }
  }
}

// --- Email Section ---
msg += `\n━━━━━━━━━━━━━━━━━━━━\n`;
msg += `📧 *UNREAD EMAILS*`;

// Deduplicate emails
const seenEmails = new Set();
const uniqueEmails = emails.filter(i => {
  const id = i.json.id || i.json.threadId;
  if (seenEmails.has(id)) return false;
  seenEmails.add(id);
  return true;
});

if (uniqueEmails.length === 0) {
  msg += `\nInbox zero! 🎉\n`;
} else {
  msg += ` (${uniqueEmails.length})\n`;
  const sorted = uniqueEmails.map(i => {
    const subj = i.json.subject || i.json.Subject || 'No Subject';
    const snippet = i.json.snippet || '';
    const urgency = getEmailUrgency(`${subj} ${snippet}`);
    const sender = getSender(i.json);
    return { urgency, subject: subj, sender, id: i.json.id };
  }).sort((a, b) => {
    const order = { '🔴': 0, '🟠': 1, '🟡': 2, '⚪': 3 };
    return (order[a.urgency] ?? 4) - (order[b.urgency] ?? 4);
  });

  const shown = sorted.slice(0, 8);
  for (const e of shown) {
    const shortSubj = e.subject.length > 50 ? e.subject.substring(0, 47) + '...' : e.subject;
    msg += `\n${e.urgency} [${esc(shortSubj)}](https://mail.google.com/mail/u/0/#inbox/${e.id})\n`;
    msg += `    👤 ${esc(e.sender)}\n`;
  }
  if (sorted.length > 8) {
    msg += `\n_...and ${sorted.length - 8} more_\n`;
  }
}

msg += `\n━━━━━━━━━━━━━━━━━━━━\n`;
msg += `Have a great day! 💪`;

return [{ json: { reminderMessage: msg, messageType: 'morning_briefing' } }];

