const emails = emailItems.filter(i => !i.json?.error && i.json?.id);
let msg = `📬 *Evening Email Digest*\n`;
const now = new Date();
msg += `${now.toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'short', timeZone: CONFIG.timezone })}\n`;
if (emails.length === 0) {
  msg += `\nAll caught up! No unread emails. 🎉\n`;
} else {
  const categorized = emails.map(i => {
    const subj = i.json.subject || i.json.Subject || 'No Subject';
    const snippet = i.json.snippet || '';
    const cat = getCategory(`${subj} ${snippet}`);
    return { ...cat, subject: subj, sender: getSender(i.json), id: i.json.id, snippet };
  });
  const groups = {};
  for (const e of categorized) {
    if (!groups[e.label]) groups[e.label] = { icon: e.icon, order: e.order, items: [] };
    groups[e.label].items.push(e);
  }
  const sortedGroups = Object.entries(groups).sort((a, b) => a[1].order - b[1].order);
  msg += `\n📊 *${emails.length} unread email${emails.length > 1 ? 's' : ''}*\n`;
  for (const [label, group] of sortedGroups) {
    msg += `\n${group.icon} *${label}* (${group.items.length})\n`;
    const shown = group.items.slice(0, 5);
    for (const e of shown) {
      const shortSubj = e.subject.length > 45 ? e.subject.substring(0, 42) + '...' : e.subject;
      msg += `  • [${esc(shortSubj)}](https://mail.google.com/mail/u/0/#inbox/${e.id})\n`;
      msg += `    _${esc(e.sender)}_\n`;
    }
    if (group.items.length > 5) {
      msg += `  _...+${group.items.length - 5} more_\n`;
    }
  }
  const actionCount = (groups['Urgent']?.items.length || 0) + (groups['Action Required']?.items.length || 0);
  if (actionCount > 0) {
    msg += `\n⚠️ *${actionCount} email${actionCount > 1 ? 's' : ''} need${actionCount === 1 ? 's' : ''} your attention*\n`;
  }
}
msg += `\n[Open Gmail](https://mail.google.com/mail/u/0/#inbox)`;
return [{ json: { reminderMessage: msg, messageType: 'email_digest' } }];
